337:     public void handleAssignment(final Map<TaskId, Set<TopicPartition>> activeTasks,
338:                                  final Map<TaskId, Set<TopicPartition>> standbyTasks) {
339:         log.info("Handle new assignment with:\n" +
340:                      "\tNew active tasks: {}\n" +
341:                      "\tNew standby tasks: {}\n" +
342:                      "\tExisting active tasks: {}\n" +
343:                      "\tExisting standby tasks: {}",
344:                  activeTasks.keySet(), standbyTasks.keySet(), activeTaskIds(), standbyTaskIds());
345: 
346:         topologyMetadata.addSubscribedTopicsFromAssignment(
347:             activeTasks.values().stream().flatMap(Collection::stream).collect(Collectors.toSet()),
348:             logPrefix
349:         );
350: 
351:         final Map<TaskId, Set<TopicPartition>> activeTasksToCreate = new HashMap<>(activeTasks);
352:         final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate = new HashMap<>(standbyTasks);
353:         final Map<Task, Set<TopicPartition>> tasksToRecycle = new HashMap<>();
354:         final Set<Task> tasksToCloseClean = new TreeSet<>(Comparator.comparing(Task::id));
355: 
356:         final Set<TaskId> tasksToLock =
357:             tasks.allTaskIds().stream()
358:                 .filter(x -> activeTasksToCreate.containsKey(x) || standbyTasksToCreate.containsKey(x))
359:                 .collect(Collectors.toSet());
360: 
361:         maybeLockTasks(tasksToLock);
362: 
363:         // first put aside those unrecognized tasks because of unknown named-topologies
364:         tasks.clearPendingTasksToCreate();
365:         tasks.addPendingActiveTasksToCreate(pendingTasksToCreate(activeTasksToCreate));
366:         tasks.addPendingStandbyTasksToCreate(pendingTasksToCreate(standbyTasksToCreate));
367:         
368:         // first rectify all existing tasks:
369:         // 1. for tasks that are already owned, just update input partitions / resume and skip re-creating them
370:         // 2. for tasks that have changed active/standby status, just recycle and skip re-creating them
371:         // 3. otherwise, close them since they are no longer owned
372:         final Map<TaskId, RuntimeException> failedTasks = new LinkedHashMap<>();
373:         if (stateUpdater == null) {
374:             handleTasksWithoutStateUpdater(activeTasksToCreate, standbyTasksToCreate, tasksToRecycle, tasksToCloseClean);
375:         } else {
376:             handleTasksWithStateUpdater(
377:                 activeTasksToCreate,
378:                 standbyTasksToCreate,
379:                 tasksToRecycle,
380:                 tasksToCloseClean,
381:                 failedTasks
382:             );
383:             failedTasks.putAll(collectExceptionsAndFailedTasksFromStateUpdater());
384:         }
385: 
386:         final Map<TaskId, RuntimeException> taskCloseExceptions = closeAndRecycleTasks(tasksToRecycle, tasksToCloseClean);
387: 
388:         maybeUnlockTasks(tasksToLock);
389: 
390:         failedTasks.putAll(taskCloseExceptions);
391:         maybeThrowTaskExceptions(failedTasks);
392: 
393:         createNewTasks(activeTasksToCreate, standbyTasksToCreate);
394:     }
395: 
396:     // Wrap and throw the exception in the following order
397:     // if at least one of the exception is a non-streams exception, then wrap and throw since it should be handled by thread's handler
398:     // if at least one of the exception is a streams exception, then directly throw since it should be handled by thread's handler
399:     // if at least one of the exception is a task-migrated exception, then directly throw since it indicates all tasks are lost
400:     // otherwise, all the exceptions are task-corrupted, then merge their tasks and throw a single one
401:     // TODO: move task-corrupted and task-migrated out of the public errors package since they are internal errors and always be
402:     //       handled by Streams library itself
403:     private void maybeThrowTaskExceptions(final Map<TaskId, RuntimeException> taskExceptions) {
404:         if (!taskExceptions.isEmpty()) {
405:             log.error("Get exceptions for the following tasks: {}", taskExceptions);
406: 
407:             final Set<TaskId> aggregatedCorruptedTaskIds = new HashSet<>();
408:             StreamsException lastFatal = null;
409:             TaskMigratedException lastTaskMigrated = null;
410:             for (final Map.Entry<TaskId, RuntimeException> entry : taskExceptions.entrySet()) {
411:                 final TaskId taskId = entry.getKey();
412:                 final RuntimeException exception = entry.getValue();
413: 
414:                 if (exception instanceof StreamsException) {
415:                     if (exception instanceof TaskMigratedException) {
416:                         lastTaskMigrated = (TaskMigratedException) exception;
417:                     } else if (exception instanceof TaskCorruptedException) {
418:                         log.warn("Encounter corrupted task " + taskId + ", will group it with other corrupted tasks " +
419:                             "and handle together", exception);
420:                         aggregatedCorruptedTaskIds.add(taskId);
421:                     } else {
422:                         ((StreamsException) exception).setTaskId(taskId);
423:                         lastFatal = (StreamsException) exception;
424:                     }
425:                 } else if (exception instanceof KafkaException) {
426:                     lastFatal = new StreamsException(exception, taskId);
427:                 } else {
428:                     lastFatal = new StreamsException("Encounter unexpected fatal error for task " + taskId, exception, taskId);
429:                 }
430:             }
431: 
432:             if (lastFatal != null) {
433:                 throw lastFatal;
434:             } else if (lastTaskMigrated != null) {
435:                 throw lastTaskMigrated;
436:             } else {
437:                 throw new TaskCorruptedException(aggregatedCorruptedTaskIds);
438:             }
439:         }
440:     }
